mapper.select:
SELECT m.* FROM monitor_snapshot m
INNER JOIN (
    SELECT node_id, MAX(collect_time) AS max_time FROM monitor_snapshot
    WHERE project_id = #{projectId} GROUP BY node_id
) t ON m.node_id = t.node_id AND m.collect_time = t.max_time AND m.project_id = #{projectId}

SELECT * FROM monitor_snapshot
WHERE project_id = #{projectId}
AND node_id = #{nodeId}
AND collect_time >= #{startTime}
AND collect_time <= #{endTime}
ORDER BY collect_time ASC
LIMIT #{limit}

SELECT * FROM monitor_snapshot
WHERE project_id = #{projectId}
AND node_id = #{nodeId}
ORDER BY collect_time DESC
LIMIT #{limit}

SELECT COUNT(*) FROM monitor_snapshot
WHERE project_id = #{projectId}
AND node_id = #{nodeId}
AND health_status = 'DOWN' AND collect_time >= #{startTime}
